// Helper: get YoY % change between two years for a given slug.
export function yoyChange(slug, fromYear, toYear) {
  const series = PRODUCTION_TIMESERIES[slug];
  if (!series) return null;
  const a = series[fromYear], b = series[toYear];
  if (a == null || b == null) return null;
  return ((b - a) / a) * 100;
}

// Helper: get 7-year trend label.
export function trendLabel(slug) {
  const series = PRODUCTION_TIMESERIES[slug];
  if (!series) return null;
  const start = series[2018], end = series[2024];
  if (start == null || end == null) return null;
  const pct = ((end - start) / start) * 100;
  if (pct > 8) return { dir: 'rising', pct, sym: '↑' };
  if (pct < -8) return { dir: 'declining', pct, sym: '↓' };
  return { dir: 'stable', pct, sym: '→' };
}
